/// <summary>
/// 构建完地图后，把从 Tilemap 追踪到的路径点刷到场景的 PathCreator 上，
/// 确保敌人走当前关卡的路径。
/// </summary>
private void UpdatePathCreator()
{
    var pathCreator = FindObjectOfType<PathCreator>();
    if (pathCreator == null)
    {
        Debug.LogWarning("[LevelBuilder] 场景中没有 PathCreator，跳过路径更新");
        return;
    }

    var waypoints = GetPathWaypoints();
    if (waypoints.Count == 0)
    {
        Debug.LogWarning("[LevelBuilder] 从 Tilemap 追踪到 0 个路径点，未更新 PathCreator");
        return;
    }

    pathCreator.ClearPath();
    foreach (var wp in waypoints)
    {
        pathCreator.AddWaypoint(wp);
    }

    Debug.Log($"[LevelBuilder] PathCreator 已更新: {waypoints.Count} 个路径点");
}

