// Read all tilemaps under the Grid and dump ASCII map
var grid = Object.FindObjectOfType<Grid>();
if (grid == null) { Debug.Log("No Grid found!"); return; }

// Get all tilemaps
var tilemaps = grid.GetComponentsInChildren<Tilemap>();
Debug.Log($"Found {tilemaps.Length} tilemaps under Grid:");

// Find the specific tilemaps by name
Tilemap groundMap = null, pathMap = null, buildSlotMap = null, decoMap = null;
foreach (var tm in tilemaps)
{
    Debug.Log($"  - {tm.name} (cellBounds: {tm.cellBounds})");
    if (tm.name.Contains("草地") || tm.name.Contains("Ground") || tm.name.Contains("ground")) groundMap = tm;
    if (tm.name.Contains("路径") || tm.name.Contains("Path") || tm.name.Contains("path")) pathMap = tm;
    if (tm.name.Contains("建造") || tm.name.Contains("Build") || tm.name.Contains("build") || tm.name.Contains("槽")) buildSlotMap = tm;
    if (tm.name.Contains("装饰") || tm.name.Contains("Deco") || tm.name.Contains("deco")) decoMap = tm;
}

Debug.Log($"Resolved: ground={groundMap?.name}, path={pathMap?.name}, build={buildSlotMap?.name}, deco={decoMap?.name}");

// Get combined bounds
BoundsInt bounds = new BoundsInt();
foreach (var tm in tilemaps)
{
    if (tm.cellBounds.size.x > 0)
    {
        BoundsInt cb = tm.cellBounds;
        if (bounds.size.x == 0)
            bounds = cb;
        else
        {
            int xMin = Mathf.Min(bounds.xMin, cb.xMin);
            int yMin = Mathf.Min(bounds.yMin, cb.yMin);
            int xMax = Mathf.Max(bounds.xMax, cb.xMax);
            int yMax = Mathf.Max(bounds.yMax, cb.yMax);
            bounds = new BoundsInt(xMin, yMin, 0, xMax - xMin, yMax - yMin, 1);
        }
    }
}

Debug.Log($"Combined bounds: x={bounds.xMin}..{bounds.xMax}, y={bounds.yMin}..{bounds.yMax}");

// Build ASCII map (y goes from top to bottom = max to min)
var rows = new System.Collections.Generic.List<string>();
for (int y = bounds.yMax - 1; y >= bounds.yMin; y--)
{
    var row = new System.Text.StringBuilder();
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    {
        var cell = new Vector3Int(x, y, 0);
        bool hasPath = pathMap != null && pathMap.GetTile(cell) != null;
        bool hasBuild = buildSlotMap != null && buildSlotMap.GetTile(cell) != null;
        bool hasGround = groundMap != null && groundMap.GetTile(cell) != null;
        bool hasDeco = decoMap != null && decoMap.GetTile(cell) != null;

        if (hasPath) row.Append('P');
        else if (hasBuild) row.Append('B');
        else if (hasDeco) row.Append('D');
        else if (hasGround) row.Append('G');
        else row.Append('.');
    }
    rows.Add(row.ToString());
}

Debug.Log("=== ASCII MAP START ===");
for (int i = 0; i < rows.Count; i++)
{
    Debug.Log($"Row {i}: {rows[i]}");
}
Debug.Log("=== ASCII MAP END ===");
Debug.Log($"Total rows: {rows.Count}, Width: {rows.Count > 0 ? rows[0].Length : 0}");

