    if (tm.name == "建造槽") buildSlotMap = tm;
    if (tm.name == "装饰") decoMap = tm;
}

if (pathMap == null) { Debug.Log("No pathMap!"); return; }

// Collect all path cells
var pathCells = new HashSet<Vector3Int>();
BoundsInt bounds = buildSlotMap != null ? buildSlotMap.cellBounds : pathMap.cellBounds;

for (int x = bounds.xMin; x < bounds.xMax; x++)
{
    for (int y = bounds.yMin; y < bounds.yMax; y++)
    {
        var cell = new Vector3Int(x, y, 0);
        if (pathMap.GetTile(cell) != null)
            pathCells.Add(cell);
    }
}

Debug.Log("Total path cells: " + pathCells.Count);

// Find path endpoints (cells with exactly 1 path neighbor)
var endpoints = new List<Vector3Int>();
foreach (var cell in pathCells)
{
    int neighbors = 0;
    foreach (var dir in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
    {
        if (pathCells.Contains(cell + dir)) neighbors++;
    }
    if (neighbors == 1) endpoints.Add(cell);
}

