/// <summary>
/// 从路径 Tilemap 追踪起点到终点的路径点，支持多格宽路径。
/// 算法：先对宽路径做中轴线提取（只保留边缘方向上唯一的格子），
/// 再沿优先直行的策略追踪，确保走的是路径中心线而非锯齿边缘。
/// </summary>
public List<Vector3> GetPathWaypoints()
{
    var waypoints = new List<Vector3>();
    if (pathMap == null) return waypoints;

    // 收集所有路径格
    var allPathCells = new HashSet<Vector3Int>();
    BoundsInt bounds = pathMap.cellBounds;
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    for (int y = bounds.yMin; y < bounds.yMax; y++)
    {
        var c = new Vector3Int(x, y, 0);
        if (pathMap.GetTile(c) != null) allPathCells.Add(c);
    }

    if (allPathCells.Count == 0) return waypoints;

    // 提取中轴线：对于每个格子，如果同一行左右都有路径格子，说明是宽路的中间行，
    // 只保留"靠一侧"的格子（取中心偏移）以形成单格宽路径。
    var centerLine = ExtractCenterLine(allPathCells);

    // 找起点和终点：中轴线上邻居数为1的格子
    var endpoints = new List<Vector3Int>();
    foreach (var cell in centerLine)
    {
        int n = 0;
        foreach (var d in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
            if (centerLine.Contains(cell + d)) n++;
        if (n <= 1) endpoints.Add(cell);
    }

    // 如果没找到端点（环形），用 _startCell/_endCell 或边界格子
    Vector3Int start, end;
    if (endpoints.Count >= 2)
    {
        start = endpoints[0];
        end = endpoints[endpoints.Count - 1];
    }
    else if (endpoints.Count == 1)
    {
        start = endpoints[0];
        end = _endCell != Vector3Int.zero && centerLine.Contains(_endCell) ? _endCell : start;
    }
    else
    {
        start = _startCell;
        end = _endCell;
    }

    if (!centerLine.Contains(start))
    {
        // 找最靠近 _startCell 的格子
        start = FindClosest(centerLine, _startCell);
    }
    if (!centerLine.Contains(end))
    {
        end = FindClosest(centerLine, _endCell);
    }

    // 沿中轴线追踪：优先直行
    var visited = new HashSet<Vector3Int>();
    var current = start;
    Vector3Int lastDir = Vector3Int.zero;

    while (current != default && centerLine.Contains(current) && !visited.Contains(current))
    {
        visited.Add(current);
        waypoints.Add(pathMap.CellToWorld(current) + new Vector3(0.5f, 0.5f, 0));

        if (current == end) break;

        // 找下一个格子：优先延续上一方向
        Vector3Int? next = null;
        Vector3Int? altNext = null;

        foreach (var dir in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
        {
            var nb = current + dir;
            if (!visited.Contains(nb) && centerLine.Contains(nb))
            {
                if (dir == lastDir) { next = nb; break; }
                if (altNext == null) altNext = nb;
            }
        }

        if (next == null) next = altNext;

        if (next.HasValue)
        {
            lastDir = next.Value - current;
            current = next.Value;
        }
        else break;
    }

    return waypoints;
}

/// <summary>
/// 从多格宽路径中提取单格宽的中轴线。
/// 策略：对每个路径格子，如果它在某个方向上两侧都有路径格子（宽路中间），
/// 则只保留该方向上"靠中心一侧"的格子。
/// </summary>
private HashSet<Vector3Int> ExtractCenterLine(HashSet<Vector3Int> pathCells)
{
    var result = new HashSet<Vector3Int>(pathCells);

    // 水平宽路：同一列中有上下两个相邻路径格子 → 只保留下面的
    var toRemove = new HashSet<Vector3Int>();
    foreach (var cell in result)
    {
        bool up = result.Contains(cell + Vector3Int.up);
        bool down = result.Contains(cell + Vector3Int.down);
        bool left = result.Contains(cell + Vector3Int.left);
        bool right = result.Contains(cell + Vector3Int.right);

        // 水平路段（左右都有路径）且上方也有路径 → 这是宽路的上行，移除
        if (left && right && up && !down)
            toRemove.Add(cell);
        // 垂直路段（上下都有路径）且右边也有路径 → 这是宽路的右列，移除
        if (up && down && right && !left)
            toRemove.Add(cell);
    }

    foreach (var c in toRemove) result.Remove(c);
    return result;
}

private Vector3Int FindClosest(HashSet<Vector3Int> cells, Vector3Int target)
{
    Vector3Int best = Vector3Int.zero;
    float bestDist = float.MaxValue;
    foreach (var c in cells)
    {
        float d = Vector3.Distance(c, target);
        if (d < bestDist) { bestDist = d; best = c; }
    }
    return best;
}

