// Read current tilemap state
var grid = Object.FindObjectOfType<Grid>();
var tilemaps = grid.GetComponentsInChildren<Tilemap>();

Tilemap groundMap = null, pathMap = null, buildSlotMap = null, decoMap = null;
foreach (var tm in tilemaps)
{
    if (tm.name == "地面") groundMap = tm;
    if (tm.name == "路径格子") pathMap = tm;
    if (tm.name == "建造槽") buildSlotMap = tm;
    if (tm.name == "装饰") decoMap = tm;
}

BoundsInt bounds = buildSlotMap != null ? buildSlotMap.cellBounds : pathMap.cellBounds;
Debug.Log("Bounds: " + bounds);

// Find S and E from path cells at boundary
// Path cells that are on the edge of the map with only 1 path neighbor are start/end
var pathCells = new System.Collections.Generic.HashSet<Vector3Int>();
for (int x = bounds.xMin; x < bounds.xMax; x++)
for (int y = bounds.yMin; y < bounds.yMax; y++)
{
    var c = new Vector3Int(x, y, 0);
    if (pathMap != null && pathMap.GetTile(c) != null) pathCells.Add(c);
}

// Find path endpoints (cells at map boundary or with 1 neighbor)
var startCell = new Vector3Int(-1, -1, -1);
var endCell = new Vector3Int(-1, -1, -1);
var edgePathCells = new System.Collections.Generic.List<Vector3Int>();
foreach (var cell in pathCells)
{
    int neighbors = 0;
    foreach (var d in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
        if (pathCells.Contains(cell + d)) neighbors++;
    if (neighbors == 1) edgePathCells.Add(cell);
}

Debug.Log("Edge path cells: " + edgePathCells.Count);
foreach (var ep in edgePathCells)
    Debug.Log("  Edge: " + ep);

// Sort: leftmost = S, rightmost = E
if (edgePathCells.Count >= 2)
{
    edgePathCells.Sort((a, b) => a.x == b.x ? a.y.CompareTo(b.y) : a.x.CompareTo(b.x));
    startCell = edgePathCells[0];
    endCell = edgePathCells[edgePathCells.Count - 1];
}
Debug.Log("S cell: " + startCell);
Debug.Log("E cell: " + endCell);

// Build ASCII map
var rows = new System.Collections.Generic.List<string>();
for (int y = bounds.yMax - 1; y >= bounds.yMin; y--)
{
    var row = new System.Text.StringBuilder();
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    {
        var cell = new Vector3Int(x, y, 0);
        bool hasPath = pathMap != null && pathMap.GetTile(cell) != null;
        bool hasBuild = buildSlotMap != null && buildSlotMap.GetTile(cell) != null;
        bool hasGround = groundMap != null && groundMap.GetTile(cell) != null;
        bool hasDeco = decoMap != null && decoMap.GetTile(cell) != null;

        char ch;
        if (cell == startCell) ch = 'S';
        else if (cell == endCell) ch = 'E';
        else if (hasPath) ch = 'P';
        else if (hasBuild) ch = 'B';
        else if (hasDeco) ch = 'D';
        else if (hasGround) ch = 'G';
        else ch = '.';

        row.Append(ch);
    }
    rows.Add(row.ToString());
}

// Trim trailing dots from each row
for (int i = 0; i < rows.Count; i++)
{
    string r = rows[i].TrimEnd('.');
    rows[i] = r;
}

