if (pathMap == null) { Debug.Log("No pathMap!"); return; }

// Find path cells on map boundary (left edge = S candidates, bottom edge = E candidates)
BoundsInt bounds = pathMap.cellBounds;
var leftEdgePath = new System.Collections.Generic.List<Vector3Int>();
var bottomEdgePath = new System.Collections.Generic.List<Vector3Int>();
var rightEdgePath = new System.Collections.Generic.List<Vector3Int>();
var topEdgePath = new System.Collections.Generic.List<Vector3Int>();

for (int y = bounds.yMin; y < bounds.yMax; y++)
{
    if (pathMap.GetTile(new Vector3Int(bounds.xMin, y, 0)) != null)
        leftEdgePath.Add(new Vector3Int(bounds.xMin, y, 0));
    if (pathMap.GetTile(new Vector3Int(bounds.xMax - 1, y, 0)) != null)
        rightEdgePath.Add(new Vector3Int(bounds.xMax - 1, y, 0));
}
for (int x = bounds.xMin; x < bounds.xMax; x++)
{
    if (pathMap.GetTile(new Vector3Int(x, bounds.yMin, 0)) != null)
        bottomEdgePath.Add(new Vector3Int(x, bounds.yMin, 0));
    if (pathMap.GetTile(new Vector3Int(x, bounds.yMax - 1, 0)) != null)
        topEdgePath.Add(new Vector3Int(x, bounds.yMax - 1, 0));
}

Debug.Log("Left edge path: " + leftEdgePath.Count);
Debug.Log("Right edge path: " + rightEdgePath.Count);
Debug.Log("Top edge path: " + topEdgePath.Count);
Debug.Log("Bottom edge path: " + bottomEdgePath.Count);

// For tower defense: S = left edge (entry), E = bottom edge (exit)
Vector3Int startCell = Vector3Int.zero;
Vector3Int endCell = Vector3Int.zero;

if (leftEdgePath.Count > 0)
    startCell = leftEdgePath[0]; // topmost on left edge
if (bottomEdgePath.Count > 0)
    endCell = bottomEdgePath[bottomEdgePath.Count - 1]; // rightmost on bottom edge

Debug.Log("S cell: " + startCell);
Debug.Log("E cell: " + endCell);

// Now update Level_02.asset mapRows with S/E markers
var levelAsset = AssetDatabase.LoadAssetAtPath<LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
if (levelAsset == null) { Debug.LogError("Level_02.asset not found!"); return; }

var rows = levelAsset.mapRows;
if (rows == null || rows.Length == 0) { Debug.LogError("No mapRows!"); return; }

// Map cell (x,y) to row index: row = bounds.yMax - 1 - y
// Column in row: col = x - bounds.xMin
