    {
        sb[eCol] = 'E';
        Debug.Log("Placed E at row " + i + " col " + eCol);
    }
    newRows[i] = sb.ToString();
}

Debug.Log("=== FINAL MAP WITH S/E ===");
for (int i = 0; i < newRows.Length; i++)
    Debug.Log(newRows[i]);

Undo.RecordObject(levelAsset, "Add S/E markers to Level_02");
levelAsset.mapRows = newRows;
EditorUtility.SetDirty(levelAsset);
