using UnityEngine;
using UnityEngine.Tilemaps;
using TowerDefense.Data;
using TowerDefense.Map;

// Load level 2 data
var levels = GameManager.Instance != null ? GameManager.Instance.Levels : null;
if (levels == null || levels.Length < 2)
{
    // Load directly from assets
    var levelAsset = UnityEditor.AssetDatabase.LoadAssetAtPath<LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
    if (levelAsset == null) { Debug.Log("Level_02 not found!"); return; }

    Debug.Log("Level_02: " + levelAsset.levelName);
    Debug.Log("mapRows: " + levelAsset.mapRows.Length);
    for (int i = 0; i < levelAsset.mapRows.Length; i++)
        Debug.Log("  Row " + i + ": " + levelAsset.mapRows[i]);
}
else
{
    var level2 = levels[1];
    Debug.Log("Level_02: " + level2.levelName);
    Debug.Log("mapRows: " + level2.mapRows.Length);
    for (int i = 0; i < level2.mapRows.Length; i++)
        Debug.Log("  Row " + i + ": " + level2.mapRows[i]);
}

// Test GetPathWaypoints with the new algorithm
var levelBuilder = Object.FindObjectOfType<LevelBuilder>();
if (levelBuilder != null)
{
    // Build level 2 first
    var levelAsset = UnityEditor.AssetDatabase.LoadAssetAtPath<LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
    if (levelAsset != null)
    {
        levelBuilder.BuildLevel(levelAsset);

        var waypoints = levelBuilder.GetPathWaypoints();
        Debug.Log("Traced waypoints count: " + waypoints.Count);
        for (int i = 0; i < waypoints.Count; i++)
            Debug.Log("  wp[" + i + "]: " + waypoints[i]);
    }
}

args.new_string:
/// <summary>
/// 从路径 Tilemap 追踪起点到终点的路径点，支持多格宽路径。
/// 使用 BFS 找最短路，再用方向优先追踪提取拐点。
/// </summary>
public List<Vector3> GetPathWaypoints()
{
    var waypoints = new List<Vector3>();
    if (pathMap == null) return waypoints;

    // 收集所有路径格
    var pathCells = new HashSet<Vector3Int>();
    BoundsInt bounds = pathMap.cellBounds;
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    for (int y = bounds.yMin; y < bounds.yMax; y++)
    {
        var c = new Vector3Int(x, y, 0);
        if (pathMap.GetTile(c) != null) pathCells.Add(c);
    }

    if (pathCells.Count == 0) return waypoints;

    // 确定 S 和 E
    Vector3Int start = _startCell;
    Vector3Int end = _endCell;

    // 如果 _startCell/_endCell 不在路径上，从边界找
    if (!pathCells.Contains(start) || !pathCells.Contains(end))
    {
        var edgeCells = new List<Vector3Int>();
        foreach (var cell in pathCells)
        {
            bool onEdge = cell.x == bounds.xMin || cell.x == bounds.xMax - 1 ||
                          cell.y == bounds.yMin || cell.y == bounds.yMax - 1;
            if (onEdge) edgeCells.Add(cell);
        }
        if (!pathCells.Contains(start) && edgeCells.Count > 0)
        {
            edgeCells.Sort((a, b) => a.x == b.x ? a.y.CompareTo(b.y) : a.x.CompareTo(b.x));
            start = edgeCells[0];
        }
        if (!pathCells.Contains(end) && edgeCells.Count > 1)
        {
            edgeCells.Sort((a, b) => a.x == b.x ? b.y.CompareTo(a.y) : b.x.CompareTo(a.x));
            end = edgeCells[0];
        }
    }

    if (!pathCells.Contains(start) || !pathCells.Contains(end)) return waypoints;

    // BFS 从 start 到 end
    var prev = new Dictionary<Vector3Int, Vector3Int>();
    var queue = new Queue<Vector3Int>();
    var visited = new HashSet<Vector3Int>();
    queue.Enqueue(start);
    visited.Add(start);
    prev[start] = start;

    while (queue.Count > 0)
    {
        var cur = queue.Dequeue();
        if (cur == end) break;

        foreach (var dir in new[] { Vector3Int.right, Vector3Int.up, Vector3Int.left, Vector3Int.down })
        {
            var nb = cur + dir;
            if (pathCells.Contains(nb) && !visited.Contains(nb))
            {
                visited.Add(nb);
                prev[nb] = cur;
                queue.Enqueue(nb);
            }
        }
    }

    // 回溯路径
    if (!prev.ContainsKey(end)) return waypoints;

    var path = new List<Vector3Int>();
    var node = end;
    while (node != start)
    {
        path.Add(node);
        node = prev[node];
    }
    path.Add(start);
    path.Reverse();

    // 简化：只保留拐点（方向改变的格子）
    var simplified = new List<Vector3Int> { path[0] };
    for (int i = 1; i < path.Count - 1; i++)
    {
        var dirBefore = path[i] - path[i - 1];
        var dirAfter = path[i + 1] - path[i];
        if (dirBefore != dirAfter)
            simplified.Add(path[i]);
    }
    simplified.Add(path[path.Count - 1]);

    // 转为世界坐标
    foreach (var cell in simplified)
    {
        waypoints.Add(pathMap.CellToWorld(cell) + new Vector3(0.5f, 0.5f, 0));
    }

    return waypoints;
}

args.old_string:
/// <summary>
/// 从路径 Tilemap 追踪起点到终点的路径点，支持多格宽路径。
/// 算法：先对宽路径做中轴线提取（只保留边缘方向上唯一的格子），
/// 再沿优先直行的策略追踪，确保走的是路径中心线而非锯齿边缘。
/// </summary>
public List<Vector3> GetPathWaypoints()
{
    var waypoints = new List<Vector3>();
    if (pathMap == null) return waypoints;

    // 收集所有路径格
    var allPathCells = new HashSet<Vector3Int>();
    BoundsInt bounds = pathMap.cellBounds;
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    for (int y = bounds.yMin; y < bounds.yMax; y++)
    {
        var c = new Vector3Int(x, y, 0);
        if (pathMap.GetTile(c) != null) allPathCells.Add(c);
    }

    if (allPathCells.Count == 0) return waypoints;

    // 提取中轴线：对于每个格子，如果同一行左右都有路径格子，说明是宽路的中间行，
    // 只保留"靠一侧"的格子（取中心偏移）以形成单格宽路径。
    var centerLine = ExtractCenterLine(allPathCells);

    // 找起点和终点：中轴线上邻居数为1的格子
    var endpoints = new List<Vector3Int>();
    foreach (var cell in centerLine)
    {
        int n = 0;
        foreach (var d in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
            if (centerLine.Contains(cell + d)) n++;
        if (n <= 1) endpoints.Add(cell);
    }

    // 如果没找到端点（环形），用 _startCell/_endCell 或边界格子
    Vector3Int start, end;
    if (endpoints.Count >= 2)
    {
        start = endpoints[0];
        end = endpoints[endpoints.Count - 1];
    }
    else if (endpoints.Count == 1)
    {
        start = endpoints[0];
        end = _endCell != Vector3Int.zero && centerLine.Contains(_endCell) ? _endCell : start;
    }
    else
    {
        start = _startCell;
        end = _endCell;
    }

    if (!centerLine.Contains(start))
    {
        // 找最靠近 _startCell 的格子
        start = FindClosest(centerLine, _startCell);
    }
    if (!centerLine.Contains(end))
    {
        end = FindClosest(centerLine, _endCell);
    }

    // 沿中轴线追踪：优先直行
    var visited = new HashSet<Vector3Int>();
    var current = start;
    Vector3Int lastDir = Vector3Int.zero;

    while (current != default && centerLine.Contains(current) && !visited.Contains(current))
    {
        visited.Add(current);
        waypoints.Add(pathMap.CellToWorld(current) + new Vector3(0.5f, 0.5f, 0));

        if (current == end) break;

        // 找下一个格子：优先延续上一方向
        Vector3Int? next = null;
        Vector3Int? altNext = null;

        foreach (var dir in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
        {
            var nb = current + dir;
            if (!visited.Contains(nb) && centerLine.Contains(nb))
            {
                if (dir == lastDir) { next = nb; break; }
                if (altNext == null) altNext = nb;
            }
        }

        if (next == null) next = altNext;

        if (next.HasValue)
        {
            lastDir = next.Value - current;
            current = next.Value;
        }
        else break;
    }

    return waypoints;
}

/// <summary>
/// 从多格宽路径中提取单格宽的中轴线。
/// 策略：对每个路径格子，如果它在某个方向上两侧都有路径格子（宽路中间），
/// 则只保留该方向上"靠中心一侧"的格子。
/// </summary>
private HashSet<Vector3Int> ExtractCenterLine(HashSet<Vector3Int> pathCells)
{
    var result = new HashSet<Vector3Int>(pathCells);

    // 水平宽路：同一列中有上下两个相邻路径格子 → 只保留下面的
    var toRemove = new HashSet<Vector3Int>();
    foreach (var cell in result)
    {
        bool up = result.Contains(cell + Vector3Int.up);
        bool down = result.Contains(cell + Vector3Int.down);
        bool left = result.Contains(cell + Vector3Int.left);
        bool right = result.Contains(cell + Vector3Int.right);

        // 水平路段（左右都有路径）且上方也有路径 → 这是宽路的上行，移除
        if (left && right && up && !down)
            toRemove.Add(cell);
        // 垂直路段（上下都有路径）且右边也有路径 → 这是宽路的右列，移除
        if (up && down && right && !left)
            toRemove.Add(cell);
    }

    foreach (var c in toRemove) result.Remove(c);
    return result;
}

private Vector3Int FindClosest(HashSet<Vector3Int> cells, Vector3Int target)
{
    Vector3Int best = Vector3Int.zero;
    float bestDist = float.MaxValue;
    foreach (var c in cells)
    {
        float d = Vector3.Distance(c, target);
        if (d < bestDist) { bestDist = d; best = c; }
    }
    return best;
}

