[Header("Settings")]
[SerializeField] private PathCreator _pathCreator;
[SerializeField] private Transform _spawnPoint;

/// <summary>当前关卡的所有可用路径，每帧自动从场景刷新</summary>
private List<PathCreator> _allPaths = new List<PathCreator>();

private void Awake()
{
    RefreshPaths();
    if (_allPaths.Count > 0)
    {
        _pathCreator = _allPaths[0];
        Debug.Log("EnemySpawner: 找到 " + _allPaths.Count + " 条路径，默认使用: " + _pathCreator.gameObject.name);
    }
    else if (_pathCreator != null)
    {
        _allPaths.Add(_pathCreator);
    }
    else
    {
        Debug.LogError("EnemySpawner: 找不到任何 PathCreator！");
    }
}

/// <summary>刷新场景中的所有 PathCreator</summary>
public void RefreshPaths()
{
    _allPaths.Clear();
    _allPaths.AddRange(FindObjectsOfType<PathCreator>());
}

/// <summary>随机选一条路径</summary>
private PathCreator PickRandomPath()
{
    if (_allPaths.Count == 0) RefreshPaths();
    if (_allPaths.Count == 0) return _pathCreator;
    if (_allPaths.Count == 1) return _allPaths[0];
    return _allPaths[Random.Range(0, _allPaths.Count)];
}

Vector3 spawnPos = _spawnPoint != null ? _spawnPoint.position : (_pathCreator != null ? _pathCreator.GetWaypoint(0) : transform.position);

