using UnityEngine;
using UnityEngine.Tilemaps;
using UnityEditor;
using TowerDefense.Data;

// Read current tilemap state from scene
var grid = Object.FindObjectOfType<Grid>();
var tilemaps = grid.GetComponentsInChildren<Tilemap>();
Tilemap groundMap = null, pathMap = null, buildSlotMap = null, decoMap = null;
foreach (var tm in tilemaps)
{
    if (tm.name == "地面") groundMap = tm;
    if (tm.name == "路径格子") pathMap = tm;
    if (tm.name == "建造槽") buildSlotMap = tm;
    if (tm.name == "装饰") decoMap = tm;
}

BoundsInt bounds = buildSlotMap != null ? buildSlotMap.cellBounds : pathMap.cellBounds;
Debug.Log("Bounds: " + bounds);

// Dump current map state with exact cell data
var rows = new System.Collections.Generic.List<string>();
for (int y = bounds.yMax - 1; y >= bounds.yMin; y--)
{
    var row = new System.Text.StringBuilder();
    for (int x = bounds.xMin; x < bounds.xMax; x++)
    {
        var cell = new Vector3Int(x, y, 0);
        bool hasPath = pathMap != null && pathMap.GetTile(cell) != null;
        bool hasBuild = buildSlotMap != null && buildSlotMap.GetTile(cell) != null;
        bool hasGround = groundMap != null && groundMap.GetTile(cell) != null;
        bool hasDeco = decoMap != null && decoMap.GetTile(cell) != null;

        if (hasPath) row.Append('P');
        else if (hasBuild) row.Append('B');
        else if (hasDeco) row.Append('D');
        else if (hasGround) row.Append('G');
        else row.Append('.');
    }
    rows.Add(row.ToString());
}

// Show the map for reference
for (int i = 0; i < rows.Count; i++)
    Debug.Log("Row " + i + ": " + rows[i]);

// Now design the fork map. The fork point is at the left PP column.
// Upper branch: rows 1-2 (change P to 1)
// Lower branch: rows 6-7 (change P to 2)
// Also need to connect the lower path (fill gap in rows 6-7)

// Current row analysis:
// Row 2: has horizontal P path (upper) - cols ~5-24
// Row 3: has horizontal P path (upper) - cols ~5-23
// Row 6: has middle P path - cols ~5,11-24
// Row 7: has middle P path - cols ~0-6,11-24
// Left PP column: cols ~5-6, rows 2-8
// Right PP column: cols ~23-24, rows 2-15

// For fork: 
// - Upper path (1): goes through rows 2-3 (change to 1)
// - Lower path (2): goes through rows 6-7 connecting left to right (change to 2, fill gap)
// - Shared: left PP column (P), right PP column (P), S entry (P)

var newRows = new string[rows.Count];
for (int i = 0; i < rows.Count; i++)
    newRows[i] = rows[i];

// Row 2 (index 2): upper horizontal → change P to 1
var sb2 = new System.Text.StringBuilder(newRows[2]);
for (int c = 0; c < sb2.Length; c++) if (sb2[c] == 'P') sb2[c] = '1';
newRows[2] = sb2.ToString();

// Row 3: upper horizontal → change P to 1  
var sb3 = new System.Text.StringBuilder(newRows[3]);
for (int c = 0; c < sb3.Length; c++) if (sb3[c] == 'P') sb3[c] = '1';
newRows[3] = sb3.ToString();

// Row 6: lower path. Need to fill gap between left PP (col ~5-6) and middle path (col ~11+)
// Change existing P to 2, and fill the gap (cols 7-10) with 2
var sb6 = new System.Text.StringBuilder(newRows[6]);
for (int c = 0; c < sb6.Length; c++)
{
    if (sb6[c] == 'P') sb6[c] = '2';
}
// Fill gap: change B/G between the left path section and middle section to '2'
// Find where the left P/2 section ends and the gap begins
// In row 6: cols 5 is P(now 2), cols 6 is B/G, then gap, then cols 11+ are P(now 2)
// Let's find and fill the gap
bool foundPath = false;
bool inGap = false;
for (int c = 0; c < sb6.Length; c++)
{
    if (sb6[c] == '2') foundPath = true;
    if (foundPath && sb6[c] != '2' && sb6[c] != '1') inGap = true;
    if (inGap && sb6[c] == '2') inGap = false; // gap ended
    if (inGap) sb6[c] = '2';
}
newRows[6] = sb6.ToString();

// Row 7: same treatment - lower path, fill gap
var sb7 = new System.Text.StringBuilder(newRows[7]);
for (int c = 0; c < sb7.Length; c++)
{
    if (sb7[c] == 'P') sb7[c] = '2';
}
foundPath = false;
inGap = false;
for (int c = 0; c < sb7.Length; c++)
{
    if (sb7[c] == '2') foundPath = true;
    if (foundPath && sb7[c] != '2' && sb7[c] != '1') inGap = true;
    if (inGap && sb7[c] == '2') inGap = false;
    if (inGap) sb7[c] = '2';
}
newRows[7] = sb7.ToString();

// Place S and E markers
// Find S: leftmost path cell on left edge
for (int i = 0; i < newRows.Length; i++)
{
    var sb = new System.Text.StringBuilder(newRows[i]);
    // S at row where left edge has path
    if (sb[0] == 'P' || sb[0] == '2')
    {
        sb[0] = 'S';
        newRows[i] = sb.ToString();
        break;
    }
}
// E at bottom-right path cell
for (int i = newRows.Length - 1; i >= 0; i--)
{
    var sb = new System.Text.StringBuilder(newRows[i]);
    for (int c = sb.Length - 1; c >= 0; c--)
    {
        if (sb[c] == 'P' || sb[c] == '1' || sb[c] == '2')
        {
            sb[c] = 'E';
            newRows[i] = sb.ToString();
            break;
        }
    }
    if (newRows[i].Contains("E")) break;
}

Debug.Log("=== FORK MAP ===");
for (int i = 0; i < newRows.Length; i++)
    Debug.Log(newRows[i]);

// Save to Level_02.asset
var levelAsset = AssetDatabase.LoadAssetAtPath<LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
if (levelAsset != null)
{
    Undo.RecordObject(levelAsset, "Update Level_02 fork map");
    // Trim trailing dots
    var trimmed = new System.Collections.Generic.List<string>();
    foreach (var r in newRows)
        trimmed.Add(r.TrimEnd('.'));
    levelAsset.mapRows = trimmed.ToArray();
    EditorUtility.SetDirty(levelAsset);
    AssetDatabase.SaveAssets();
    Debug.Log("Level_02.asset SAVED with fork map!");
}

using UnityEditor;
using TowerDefense.Data;

var levelAsset = AssetDatabase.LoadAssetAtPath<LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
if (levelAsset == null) { Debug.Log("Not found!"); return; }

// Hand-craft the fork map: 
// 1=upper branch, 2=lower branch, P=shared path
// Left PP column at col 5-6 goes up from row 6 to row 2 (connecting shared→upper)
// Right PP column at col 23-24 goes from row 2 down to row 15 (merge)
// Upper: rows 2-3 horizontal (1), connecting left PP to right PP
// Lower: rows 6-7 horizontal (2), connecting left side to right PP
// The fork is at col 5-6 row 6: go UP (1) or continue RIGHT (2)

var map = new string[]
{
    "BBBBBBBBBBBBBGGBBBBBBBBBBBBBBBB",   // Row 0
    "BBBBBBBBBBBBBBGGBBBBBBBBBBBBBBBB",   // Row 1
    "BBBBB11111111111111111111BBBBBB",     // Row 2: 1=upper horizontal
    "BBBBB11111111111111111111BBBBB",      // Row 3: 1=upper horizontal
    "BBBBBPPBBBBBBBBBBBBBBBBPPBBBBB",      // Row 4: P=fork left PP + merge right PP
    "BBBBBPPBBBGGGGGGGGBBBBPPBBBB",       // Row 5: P=shared columns + deco
    "SPPPPP22222222222222222PPBBBBB",      // Row 6: S+shared P then 2=lower branch, PP=right PP
    "BBBBBB222222222222222222PPBBBBB",     // Row 7: 2=lower branch, PP=right PP
    "BBBBBBBBBBBBPPBBBBBGGBBBPPBBBBB",     // Row 8: P=right PP column
    "BBBBBBBBBBBPPBBBBBBGGBBBPPBBBBB",     // Row 9: P=right PP column
    "BBBBBDDDBBBPPGGGGGGGGBBPPDDBBB",      // Row 10: P=right PP + deco
    "BBBBBDDDBBBPPBBBBBBBBBBPPDDBBB",      // Row 11
    "BBBBBBBBBBBPPBBBBBBBBBBPPBBBBB",      // Row 12
    "BBBBBBBBBBBPPBBBBBBBBBBPPBBBBB",      // Row 13
    "GGGGGGGGGGGPPGGGGGGGGGGPPGGGGG",      // Row 14
    "GGGGGGGGGGGPPGGGGGGGGGGPEGGGGG",      // Row 15: E
};

