args.script:
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;
using TowerDefense.Utils;

var levelAsset = UnityEditor.AssetDatabase.LoadAssetAtPath<LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
var levelBuilder = UnityEngine.Object.FindObjectOfType<LevelBuilder>();
levelBuilder.BuildLevel(levelAsset);

// Trace Path 1 (upper) - pass null for single path, or construct branch set
var allPC = UnityEngine.Object.FindObjectsOfType<PathCreator>();
Debug.Log("PathCreators: " + allPC.Length);
foreach (var pc in allPC)
    Debug.Log("  " + pc.gameObject.name + ": " + pc.WaypointCount + " wp, first=" + pc.GetWaypoint(0) + ", last=" + pc.GetWaypoint(pc.WaypointCount - 1));

using UnityEngine;
using UnityEngine.Tilemaps;
using TowerDefense.Map;

var levelBuilder = UnityEngine.Object.FindObjectOfType<LevelBuilder>();
if (levelBuilder == null) { Debug.Log("No LevelBuilder!"); return; }

// Rebuild level 2 to see current state
var levelAsset = UnityEditor.AssetDatabase.LoadAssetAtPath<TowerDefense.Data.LevelData>("Assets/Resources/Data/Levels/Level_02.asset");
levelBuilder.BuildLevel(levelAsset);

// Get all tilemaps
var grid = UnityEngine.Object.FindObjectOfType<Grid>();
var tilemaps = grid.GetComponentsInChildren<Tilemap>();

Tilemap groundMap = null, pathMap = null, buildSlotMap = null, decoMap = null;
foreach (var tm in tilemaps)
{
    if (tm.name == "地面") groundMap = tm;
    if (tm.name == "路径格子") pathMap = tm;
    if (tm.name == "建造槽") buildSlotMap = tm;
    if (tm.name == "装饰") decoMap = tm;
}

if (buildSlotMap == null || pathMap == null) { Debug.Log("Missing tilemaps!"); return; }

BoundsInt bounds = buildSlotMap.cellBounds;

// Find empty spots: B in mapRows but no actual tile in buildSlotMap
// Also find spots where there's no path neighbor at all (dead zones)
Debug.Log("=== Checking for empty tower slot areas ===");

// Read the LevelData to check map vs tiles
var mapRows = levelAsset.mapRows;
int height = mapRows.Length;

// Find cells that have B in map but no tile rendered (gap)
// And find B cells that have no adjacent P/1/2 cells (useless tower spots that need path)
for (int row = 0; row < height; row++)
{
    string line = mapRows[row];
    for (int col = 0; col < line.Length; col++)
    {
        char c = line[col];
        var cell = new Vector3Int(col, height - 1 - row, 0);

        // Check if B cell has no path neighbor
        if (c == 'B')
        {
            bool hasPathNeighbor = false;
            foreach (var d in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
            {
                var nb = cell + d;
                // Check in map
                int nbRow = height - 1 - nb.y;
                int nbCol = nb.x;
                if (nbRow >= 0 && nbRow < height && nbCol >= 0 && nbCol < mapRows[nbRow].Length)
                {
                    char nc = mapRows[nbRow][nbCol];
                    if (nc == 'P' || nc == 'S' || nc == 'E' || (nc >= '1' && nc <= '9'))
                        hasPathNeighbor = true;
                }
            }

            if (!hasPathNeighbor)
            {
                Debug.Log("  B at col=" + col + " row=" + row + " (cell " + cell + ") has NO path neighbor - isolated tower slot!");
            }
        }

        // Check if map says there should be a tile but it's missing
